import{_ as t,o as a,c as o,ae as n}from"./chunks/framework.D5VeguZw.js";const h=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/introduction.md","filePath":"en/guide/introduction.md","lastUpdated":1782324472000}'),s={name:"en/guide/introduction.md"};function i(r,e,d,c,p,l){return a(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">Vue 3 Only</p><p>Uni Router only supports the <strong>Vue 3</strong> version of uni-app, not Vue 2. Core functionality depends on Composition API (<code>inject</code> / <code>ref</code>), <code>app.provide</code>, <code>&lt;script setup&gt;</code> and other features.</p></div><h2 id="what-it-is" tabindex="-1">What It Is <a class="header-anchor" href="#what-it-is" aria-label="Permalink to &quot;What It Is&quot;">​</a></h2><p>Uni Router is a routing management library designed for <a href="https://uniapp.dcloud.net.cn/" target="_blank" rel="noreferrer">uni-app</a>, wrapping a layer on top of uni-app&#39;s native navigation APIs to provide a <a href="https://router.vuejs.org/" target="_blank" rel="noreferrer">vue-router</a>-style API experience.</p><h2 id="why-you-need-it" tabindex="-1">Why You Need It <a class="header-anchor" href="#why-you-need-it" aria-label="Permalink to &quot;Why You Need It&quot;">​</a></h2><p>uni-app natively uses <code>uni.navigateTo</code>, <code>uni.redirectTo</code>, <code>uni.switchTab</code> and other APIs for page navigation, which has the following pain points:</p><table tabindex="0"><thead><tr><th>Pain Point</th><th>Native Solution</th><th>Uni Router Solution</th></tr></thead><tbody><tr><td>No route guards</td><td>Cannot intercept before navigation</td><td><code>beforeEach</code> / <code>beforeResolve</code> / <code>afterEach</code></td></tr><tr><td>No route meta</td><td>Cannot attach properties to routes</td><td><code>meta</code> field, supports custom extension</td></tr><tr><td>Fragmented API</td><td>Manually choose navigateTo / switchTab</td><td>Auto-select based on <code>meta.isTab</code></td></tr><tr><td>No composables</td><td>Cannot access router in setup</td><td><code>useRouter()</code> / <code>useRoute()</code></td></tr><tr><td>Inconsistent error handling</td><td>Callback-style, no structured error codes</td><td><code>NavigationFailure</code> + error codes</td></tr><tr><td>Limited param passing</td><td>Only URL query supported</td><td><code>params</code> supports complex data + persistence</td></tr></tbody></table><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>Understanding Uni Router&#39;s architecture helps you master all its features.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes one-dark-pro github-light vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                   Your Application Code              │</span></span>
<span class="line"><span>│         router.push() / useRouter() / ...            │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│                   Uni Router                         │</span></span>
<span class="line"><span>│  ┌──────────┐  ┌──────────┐  ┌───────────────────┐  │</span></span>
<span class="line"><span>│  │ Navigation │  │  Guards   │  │ Composables/Plugin│  │</span></span>
<span class="line"><span>│  │ push etc  │→│ beforeEach│  │  useRouter etc    │  │</span></span>
<span class="line"><span>│  └────┬─────┘  └────┬─────┘  └───────────────────┘  │</span></span>
<span class="line"><span>│       │             │                                │</span></span>
<span class="line"><span>│  ┌────▼─────────────▼────┐  ┌───────────────────┐   │</span></span>
<span class="line"><span>│  │  Navigation Engine     │  │  Route Matcher    │   │</span></span>
<span class="line"><span>│  │ Guards→API→State       │  │  path/name match  │   │</span></span>
<span class="line"><span>│  └────────┬──────────────┘  └───────────────────┘   │</span></span>
<span class="line"><span>│           │                                          │</span></span>
<span class="line"><span>│  ┌────────▼──────┐  ┌────────────┐  ┌────────────┐  │</span></span>
<span class="line"><span>│  │ Interceptor   │  │ Params Mgr │  │ State Sync │  │</span></span>
<span class="line"><span>│  │ interceptUniApi│  │ params Map │  │ syncRoute  │  │</span></span>
<span class="line"><span>│  └───────────────┘  └────────────┘  └────────────┘  │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│              uni-app Native Navigation API           │</span></span>
<span class="line"><span>│     uni.navigateTo / redirectTo / switchTab / ...    │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│              uni-app Page Stack (pages.json)         │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="layer-responsibilities" tabindex="-1">Layer Responsibilities <a class="header-anchor" href="#layer-responsibilities" aria-label="Permalink to &quot;Layer Responsibilities&quot;">​</a></h3><ol><li><strong>Application Layer</strong>: Your code calls <code>router.push()</code> and other APIs</li><li><strong>Uni Router Layer</strong>: Guard chain scheduling, route matching, state management, param passing</li><li><strong>uni-app Layer</strong>: Native APIs that actually execute page navigation</li><li><strong>Page Stack</strong>: Page stack managed by uni-app framework, statically declared by <code>pages.json</code></li></ol><div class="tip custom-block"><p class="custom-block-title">Key Insight</p><p>Uni Router <strong>does not replace</strong> uni-app&#39;s navigation mechanism; it adds a &quot;scheduling layer&quot; on top. All navigation ultimately executes through <code>uni.navigateTo</code> and other APIs, so all uni-app limitations (like <code>switchTab</code> not supporting query) still exist. Uni Router just provides elegant wrappers and hints on top of these limitations.</p></div><h2 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h2><h3 id="page-stack" tabindex="-1">Page Stack <a class="header-anchor" href="#page-stack" aria-label="Permalink to &quot;Page Stack&quot;">​</a></h3><p>uni-app maintains a page stack with a maximum depth of 10 (mini-program limit). Understanding the page stack is fundamental to mastering Uni Router:</p><table tabindex="0"><thead><tr><th>Operation</th><th>Stack Change</th><th>uni API</th></tr></thead><tbody><tr><td><code>push()</code></td><td>Push (+1)</td><td><code>uni.navigateTo</code></td></tr><tr><td><code>replace()</code></td><td>Replace top</td><td><code>uni.redirectTo</code></td></tr><tr><td><code>relaunch()</code></td><td>Clear then push</td><td><code>uni.reLaunch</code></td></tr><tr><td><code>back()</code></td><td>Pop (-n)</td><td><code>uni.navigateBack</code></td></tr><tr><td>TabBar switch</td><td>Close non-tab pages</td><td><code>uni.switchTab</code></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Page Stack Depth Limit</p><p>Mini-program platforms have a maximum page stack depth of <strong>10</strong>. <code>navigateTo</code> fails when exceeded. Uni Router cannot break this limit; recommend using <code>relaunch()</code> to reset the stack, or <code>back()</code> then <code>push()</code>.</p></div><h3 id="route-matching" tabindex="-1">Route Matching <a class="header-anchor" href="#route-matching" aria-label="Permalink to &quot;Route Matching&quot;">​</a></h3><p>Uni Router supports two matching methods:</p><ul><li><strong>Path matching</strong>: <code>router.push({ path: &#39;pages/about/about&#39; })</code></li><li><strong>Name matching</strong>: <code>router.push({ name: &#39;about&#39; })</code></li></ul><p>Paths are auto-normalized (leading <code>/</code> added). Name matching is safer for refactoring—just modify the route config.</p><div class="info custom-block"><p class="custom-block-title">Difference from vue-router</p><p>uni-app&#39;s page paths are determined at compile time by <code>pages.json</code> and <strong>do not support dynamic routing</strong> (like <code>/user/:id</code>). Use <code>query</code> or <code>params</code> to pass parameters.</p></div><h3 id="route-guards" tabindex="-1">Route Guards <a class="header-anchor" href="#route-guards" aria-label="Permalink to &quot;Route Guards&quot;">​</a></h3><p>Guards are Uni Router&#39;s core capability, allowing you to insert logic before/after navigation:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes one-dark-pro github-light vp-code" tabindex="0"><code><span class="line"><span>Navigation triggered</span></span>
<span class="line"><span>  → beforeEach (global pre)</span></span>
<span class="line"><span>  → beforeEnter (route-specific)</span></span>
<span class="line"><span>  → beforeResolve (global resolve)</span></span>
<span class="line"><span>  → uni API call</span></span>
<span class="line"><span>  → afterEach (global post)</span></span></code></pre></div><p>Guards can pass via <code>next()</code>, abort via <code>next(false)</code>, or redirect via <code>next(location)</code>. See <a href="./guards.html">Route Guards</a>.</p><h3 id="state-synchronization" tabindex="-1">State Synchronization <a class="header-anchor" href="#state-synchronization" aria-label="Permalink to &quot;State Synchronization&quot;">​</a></h3><p>Since physical back buttons and browser back <strong>don&#39;t go through the router</strong>, the router&#39;s <code>currentRoute</code> may be out of sync with the actual page. Uni Router provides <code>syncRoute()</code> to read the real state from the page stack and update.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes one-dark-pro github-light vp-code" tabindex="0"><code><span class="line"><span>User presses physical back</span></span>
<span class="line"><span>  → uni-app native navigateBack (bypasses router)</span></span>
<span class="line"><span>  → router currentRoute is still old value</span></span>
<span class="line"><span>  → Call syncRoute() in page onShow</span></span>
<span class="line"><span>  → currentRoute updates to real page</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">This is an inherent uni-app limitation</p><p>The router cannot intercept physical back buttons and browser back. You must call <code>syncRoute()</code> in the page&#39;s <code>onShow</code> lifecycle to maintain state consistency. See <a href="./compatibility.html">Platform Compatibility</a>.</p></div><h2 id="design-philosophy" tabindex="-1">Design Philosophy <a class="header-anchor" href="#design-philosophy" aria-label="Permalink to &quot;Design Philosophy&quot;">​</a></h2><ol><li><p><strong>Enhance, not replace</strong>: Uni Router doesn&#39;t bypass uni-app&#39;s navigation mechanism; all navigation goes through native APIs. This ensures cross-platform compatibility and means uni-app&#39;s limitations still apply.</p></li><li><p><strong>Static page model</strong>: uni-app uses <code>pages.json</code> to statically declare pages. Uni Router respects this model and doesn&#39;t provide dynamic route registration (<code>addRoute</code> / <code>removeRoute</code>).</p></li><li><p><strong>Progressive adoption</strong>: You can use just <code>push</code> / <code>replace</code> basic navigation, or enable guards, interceptors, param passing and other advanced features. <code>interceptUniApi</code> is disabled by default and doesn&#39;t affect existing code.</p></li><li><p><strong>Type safety</strong>: Through <code>@meng-xi/vite-plugin</code>&#39;s <code>dts</code> feature, route names and paths get autocompletion and type checking.</p></li></ol><h2 id="core-features-overview" tabindex="-1">Core Features Overview <a class="header-anchor" href="#core-features-overview" aria-label="Permalink to &quot;Core Features Overview&quot;">​</a></h2><ul><li>🧭 <strong>Four navigation types</strong> — <code>push</code> / <code>replace</code> / <code>relaunch</code> / <code>back</code>, auto-detect TabBar pages</li><li>🛡️ <strong>Complete guard chain</strong> — <code>beforeEach</code> / <code>beforeResolve</code> / <code>afterEach</code> / <code>beforeEnter</code></li><li>🔄 <strong>Controllable redirect</strong> — <code>next(location, { mode })</code> in guards to specify redirect method</li><li>📦 <strong>Page params</strong> — <code>params</code> passes complex data, not exposed in URL, supports persistence</li><li>🔢 <strong>Query enhancement</strong> — <code>queryInt()</code> / <code>queryNumber()</code> / <code>queryBool()</code> type parsing</li><li>📡 <strong>Page communication</strong> — <code>events</code> + <code>eventChannel</code> bidirectional communication</li><li>🎬 <strong>Navigation animation</strong> — App custom animation, route-level defaults</li><li>🪝 <strong>Composables</strong> — <code>useRouter()</code> / <code>useRoute()</code> reactive access</li><li>⚡ <strong>API interception</strong> — Optional interception of native navigation APIs, unified guard flow</li><li>🛡️ <strong>Timeout protection</strong> — <code>guardTimeout</code> / <code>readyTimeout</code> prevent hanging</li><li>💪 <strong>TypeScript</strong> — Complete type definitions + intellisense</li></ul><h2 id="what-it-is-not" tabindex="-1">What It Is Not <a class="header-anchor" href="#what-it-is-not" aria-label="Permalink to &quot;What It Is Not&quot;">​</a></h2><p>Due to uni-app framework limitations, the following vue-router features are <strong>not supported</strong>:</p><table tabindex="0"><thead><tr><th>Feature</th><th>Reason</th></tr></thead><tbody><tr><td>Dynamic route registration (<code>addRoute</code> / <code>removeRoute</code>)</td><td>uni-app pages are statically declared by <code>pages.json</code></td></tr><tr><td>Nested routes (<code>&lt;router-view&gt;</code>)</td><td>uni-app has no nested view components</td></tr><tr><td>Dynamic path matching (<code>/user/:id</code>)</td><td>uni-app page paths are fixed</td></tr><tr><td><code>router.go(n)</code> / <code>router.forward()</code></td><td>Mini-programs don&#39;t support forward navigation</td></tr><tr><td>Named views</td><td>uni-app has no multi-view support</td></tr><tr><td>Route lazy loading</td><td>uni-app has its own code splitting mechanism</td></tr><tr><td>History mode selection</td><td>uni-app uses different routing modes per platform</td></tr></tbody></table><p>These limitations stem from the uni-app framework&#39;s design, not from this library. See <a href="./differences.html">Differences from vue-router</a>.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./getting-started.html">Getting Started</a> — Integrate into your project in minutes</li><li><a href="./navigation.html">Navigation</a> — Deep dive into the four navigation methods</li><li><a href="./guards.html">Route Guards</a> — Understand guard mechanism and practices</li><li><a href="./navigation-flow.html">Navigation Flow</a> — Understand the complete navigation process from source code perspective</li></ul>`,41)])])}const g=t(s,[["render",i]]);export{h as __pageData,g as default};
